/**
 * Display user profile information securely.
 * Usage: Add shortcode [member_profile] to a page, then access via ?user_id=123
 */
function mps_display_member_profile() {
    global $wpdb;

    // Check if user_id parameter exists
    if (!isset($_GET['user_id'])) {
        return '<p>No user specified.</p>';
    }

    // Verify nonce for CSRF protection if this is a linked action
    // For public profile pages, we at minimum sanitize and validate input
    $user_id = isset($_GET['user_id']) ? absint($_GET['user_id']) : 0;

    // Validate that user_id is a positive integer
    if ($user_id <= 0) {
        return '<p>Invalid user ID.</p>';
    }

    // Optional: Restrict access to logged-in users only
    if (!is_user_logged_in()) {
        return '<p>You must be logged in to view member profiles.</p>';
    }

    // Rate limiting using transients to prevent enumeration attacks
    $current_user_id = get_current_user_id();
    $rate_limit_key = 'mps_rate_limit_' . $current_user_id;
    $rate_count = get_transient($rate_limit_key);

    if ($rate_count !== false && $rate_count > 30) {
        return '<p>Too many requests. Please try again later.</p>';
    }

    set_transient($rate_limit_key, ($rate_count ? $rate_count + 1 : 1), 60);

    // Use $wpdb->prepare() to prevent SQL injection
    // Query only the fields we need, never SELECT *
    $users_table = $wpdb->users;
    $usermeta_table = $wpdb->usermeta;

    // Use prepared statement - NEVER concatenate user input into SQL
    $user = $wpdb->get_row(
        $wpdb->prepare(
            "SELECT u.ID, u.display_name, u.user_registered
             FROM {$users_table} AS u
             WHERE u.ID = %d
             AND u.user_status = 0
             LIMIT 1",
            $user_id
        )
    );

    if (null === $user) {
        return '<p>Member not found.</p>';
    }

    // Fetch specific meta fields using prepared statements
    $allowed_meta_keys = array('first_name', 'last_name', 'description', 'membership_level');

    $placeholders = implode(',', array_fill(0, count($allowed_meta_keys), '%s'));

    $prepare_params = array_merge(array($user_id), $allowed_meta_keys);

    $meta_results = $wpdb->get_results(
        $wpdb->prepare(
            "SELECT meta_key, meta_value
             FROM {$usermeta_table}
             WHERE user_id = %d
             AND meta_key IN ({$placeholders})",
            $prepare_params
        )
    );

    $meta = array();
    if ($meta_results) {
        foreach ($meta_results as $row) {
            // Sanitize meta values on output
            $meta[$row->meta_key] = $row->meta_value;
        }
    }

    // Check if the queried user has opted into public profile visibility
    $profile_visibility = isset($meta['profile_visibility']) ? $meta['profile_visibility'] : 'public';
    // Uncomment below if you have a visibility meta field
    // if ($profile_visibility !== 'public' && $current_user_id !== $user_id) {
    //     return '<p>This member\'s profile is private.</p>';
    // }

    // Cache the result for performance with thousands of users
    $cache_key = 'mps_profile_' . $user_id;
    $cached_output = wp_cache_get($cache_key, 'mps_profiles');

    if (false !== $cached_output) {
        return $cached_output;
    }

    // Build output - escape ALL output to prevent XSS
    $output = '<div class="member-profile">';
    $output .= '<h2>' . esc_html($user->display_name) . '</h2>';

    if (!empty($meta['first_name']) || !empty($meta['last_name'])) {
        $output .= '<p class="member-name"><strong>Name:</strong> '
                  . esc_html(($meta['first_name'] ?? '') . ' ' . ($meta['last_name'] ?? ''))
                  . '</p>';
    }

    if (!empty($meta['membership_level'])) {
        $output .= '<p class="member-level"><strong>Membership:</strong> '
                  . esc_html($meta['membership_level']) . '</p>';
    }

    $output .= '<p class="member-since"><strong>Member since:</strong> '
              . esc_html(date_i18n(get_option('date_format'), strtotime($user->user_registered)))
              . '</p>';

    if (!empty($meta['description'])) {
        $output .= '<div class="member-bio"><strong>About:</strong> '
                  . wp_kses_post($meta['description']) . '</div>';
    }

    // Display gravatar securely
    $output .= '<div class="member-avatar">' . get_avatar($user_id, 150) . '</div>';

    $output .= '</div>';

    // Cache for 5 minutes
    wp_cache_set($cache_key, $output, 'mps_profiles', 300);

    return $output;
}
add_shortcode('member_profile', 'mps_display_member_profile');

/**
 * Clear profile cache when user updates their profile.
 */
function mps_clear_profile_cache($user_id) {
    wp_cache_delete('mps_profile_' . absint($user_id), 'mps_profiles');
}
add_action('profile_update', 'mps_clear_profile_cache');
add_action('updated_user_meta', function($meta_id, $user_id) {
    mps_clear_profile_cache($user_id);
}, 10, 2);

